12	/** Transforms a function call so that it can both provide implicit-style source information and
13	  * have a chained apply call. Without macros, only one is possible, since having an implicit
14	  * argument in the definition will cause the compiler to interpret a chained apply as an
15	  * explicit implicit argument and give type errors.
16	  *
17	  * Instead of an implicit argument, the public-facing function no longer takes a SourceInfo at all.
18	  * The macro transforms the public-facing function into a call to an internal function that takes
19	  * an explicit SourceInfo by inserting an implicitly[SourceInfo] as the explicit argument.
20	  */
21	trait SourceInfoTransformMacro {
22	  val c: Context
23	  import c.universe._
24	  def thisObj: Tree = c.prefix.tree
25	  def implicitSourceInfo = q"implicitly[_root_.chisel3.experimental.SourceInfo]"
26	}
