166	/** "Automatic" source information transform / insertion macros, which generate the function name
167	  * based on the macro invocation (instead of explicitly writing out every transform).
168	  */
169	abstract class AutoSourceTransform extends SourceInfoTransformMacro {
170	  import c.universe._
171	
172	  /** Returns the TermName of the transformed function, which is the applied function name with do_
173	    * prepended.
174	    */
175	  def doFuncTerm: TermName = {
176	    val funcName = c.macroApplication match {
177	      case q"$_.$funcName[..$_](...$_)" => funcName
178	      case _ =>
179	        throw new Exception(
180	          s"Chisel Internal Error: Could not resolve function name from macro application: ${showCode(c.macroApplication)}"
181	        )
182	    }
183	    TermName("do_" + funcName)
184	  }
185	}
