354	// Workaround for https://github.com/sbt/sbt/issues/3966
355	object IntLiteralApplyTransform
356	
357	class IntLiteralApplyTransform(val c: Context) extends AutoSourceTransform {
358	  import c.universe._
359	
360	  def safeApply(x: c.Tree): c.Tree = {
361	    c.macroApplication match {
362	      case q"$_.$clazz($lit).$func.apply($arg)" =>
363	        if (
364	          Set("U", "S", "asUInt", "asSInt").contains(func.toString) &&
365	          Set("fromStringToLiteral", "fromIntToLiteral", "fromLongToIteral", "fromBigIntToLiteral").contains(
366	            clazz.toString
367	          )
368	        ) {
369	          val msg =
370	            s"""Passing an Int to .$func is usually a mistake: It does *not* set the width; it does a bit extraction.
371	               |Did you mean .$func($arg.W)?
372	               |If you do want bit extraction, use .$func.extract($arg) instead.
373	               |""".stripMargin
374	          c.warning(c.enclosingPosition, msg)
375	        }
376	      case _ => // do nothing
377	    }
378	    q"$thisObj.$doFuncTerm($x)($implicitSourceInfo)"
379	  }
380	}
